// Verify /api/wind-alert honors the optional `threshold` query override.
// Using an impossibly high threshold (999 kn) deterministically forces alert=false
// regardless of live wind conditions, and the response echoes the override.
async function testWindAlertThresholdOverride() {
  const res = await fetch('http://localhost:3001/api/wind-alert?lat=41.35&lon=2.17&threshold=999');
  assertEquals(res.status, 200, 'Wind alert with override should return 200');

  const data = await res.json();
  assertEquals(data.threshold, 999, 'Response should echo the overridden threshold');
  assertEquals(data.alert, false, 'No real gusts exceed 999 kn, so alert must be false');
}
